package com.hospital.management.validation;import com.hospital.management.model.MedicalRecordForm;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;
class MedicalRecordValidatorTest {private final MedicalRecordValidator v=new MedicalRecordValidator();private MedicalRecordForm valid(){MedicalRecordForm f=new MedicalRecordForm();f.setAppointmentId(1L);f.setSymptoms("Persistent headache");f.setDiagnosis("Tension headache");f.setTreatmentNotes("Rest and hydration");f.setBloodPressure("120/80");f.setTemperature("37.2");f.setWeight("70.50");f.setHeight("175");return f;}@Test void validRecord(){assertFalse(v.validate(valid()).hasErrors());}@Test void invalidAppointment(){MedicalRecordForm f=valid();f.setAppointmentId(null);assertNotNull(v.validate(f).getError("appointmentId"));}@Test void blankSymptoms(){MedicalRecordForm f=valid();f.setSymptoms(" ");assertNotNull(v.validate(f).getError("symptoms"));}@Test void blankDiagnosis(){MedicalRecordForm f=valid();f.setDiagnosis("");assertNotNull(v.validate(f).getError("diagnosis"));}@Test void longTreatmentNotes(){MedicalRecordForm f=valid();f.setTreatmentNotes("x".repeat(4001));assertNotNull(v.validate(f).getError("treatmentNotes"));}@Test void invalidBloodPressure(){MedicalRecordForm f=valid();f.setBloodPressure("abc");assertNotNull(v.validate(f).getError("bloodPressure"));}@Test void systolicMustExceedDiastolic(){MedicalRecordForm f=valid();f.setBloodPressure("70/90");assertNotNull(v.validate(f).getError("bloodPressure"));}@Test void invalidTemperature(){MedicalRecordForm f=valid();f.setTemperature("46");assertNotNull(v.validate(f).getError("temperature"));}@Test void invalidWeight(){MedicalRecordForm f=valid();f.setWeight("0");assertNotNull(v.validate(f).getError("weight"));}@Test void invalidHeight(){MedicalRecordForm f=valid();f.setHeight("301");assertNotNull(v.validate(f).getError("height"));}}
